class AdminChangeReservationStatusView(View):
    @method_decorator(login_required)
    def post(self, request, id):
        if not request.user.is_staff:
            messages.error(request, 'Acceso denegado.')
            return redirect('catalog:home')

        reserva = get_object_or_404(Reserva, id=id)
        nuevo_estado = request.POST.get('nuevo_estado')

        # Validar transiciones de estado
        transiciones_validas = {
            'PENDIENTE_DE_PAGO': ['PAGADO', 'CANCELADA'],
            'PAGADO': ['EN_USO', 'CANCELADA'],
            'EN_USO': ['DEVUELTO'],
            'DEVUELTO': [],
            'CANCELADA': [],
        }

        if nuevo_estado not in transiciones_validas.get(reserva.estado, []):
            messages.error(request, f'Transición de estado no válida: {reserva.estado} -> {nuevo_estado}')
            return redirect('admin:reservation_detail', id=id)

        estado_anterior = reserva.estado
        reserva.estado = nuevo_estado
        reserva.save()

        CambioEstadoReserva.objects.create(
            reserva=reserva,
            estado_anterior=estado_anterior,
            estado_nuevo=nuevo_estado,
            usuario=request.user,
        )

        messages.success(request, f'Estado de reserva actualizado: {estado_anterior} -> {nuevo_estado}')
        return redirect('admin:reservation_detail', id=id)

from django import forms
from catalog.models import Barco, Categoria, Puerto, Fabricante
from django.core.exceptions import ValidationError


class BarcoForm(forms.ModelForm):
    class Meta:
        model = Barco
        fields = ['nombre', 'descripcion', 'imagen', 'categoria', 'puerto', 'fabricante', 'precio_dia', 'capacidad', 'disponible']
        widgets = {
            'nombre': forms.TextInput(attrs={
                'class': 'form-control',
                'placeholder': 'Nombre del barco'
            }),
            'descripcion': forms.Textarea(attrs={
                'class': 'form-control',
                'placeholder': 'Descripción del barco',
                'rows': 4
            }),
            'imagen': forms.FileInput(attrs={
                'class': 'form-control',
                'accept': 'image/*'
            }),
            'categoria': forms.Select(attrs={
                'class': 'form-select'
            }),
            'puerto': forms.Select(attrs={
                'class': 'form-select'
            }),
            'fabricante': forms.Select(attrs={
                'class': 'form-select'
            }),
            'precio_dia': forms.NumberInput(attrs={
                'class': 'form-control',
                'placeholder': 'Precio por día',
                'step': '0.01',
                'min': '0'
            }),
            'capacidad': forms.NumberInput(attrs={
                'class': 'form-control',
                'placeholder': 'Capacidad (personas)',
                'min': '1'
            }),
            'disponible': forms.CheckboxInput(attrs={
                'class': 'form-check-input'
            }),
        }

    def clean_nombre(self):
        nombre = self.cleaned_data.get('nombre')
        if not nombre or len(nombre.strip()) == 0:
            raise ValidationError('El nombre del barco es obligatorio.')
        return nombre

    def clean_precio_dia(self):
        precio = self.cleaned_data.get('precio_dia')
        if precio is not None and precio < 0:
            raise ValidationError('El precio por día no puede ser negativo.')
        return precio

    def clean_capacidad(self):
        capacidad = self.cleaned_data.get('capacidad')
        if capacidad is not None and capacidad < 1:
            raise ValidationError('La capacidad debe ser al menos 1 persona.')
        return capacidad

