class ReservationStep3View(View):
    def get(self, request):
        if 'nombre_cliente' not in request.session or 'metodo_pago' not in request.session:
            messages.warning(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:step1')

        sesion_id = obtener_sesion_id(request)
        items = ItemCesta.objects.filter(sesion_id=sesion_id)

        if not items.exists():
            messages.warning(request, 'La cesta está vacía.')
            return redirect('reservations:cart')

        total = Decimal('0.00')
        for item in items:
            precio_item = calcular_precio_reserva(
                item.barco,
                item.fecha_inicio,
                item.fecha_fin,
                item.cantidad
            )
            total += precio_item

        context = {
            'items': items,
            'total': total,
            'nombre_cliente': request.session.get('nombre_cliente'),
            'email_contacto': request.session.get('email_contacto'),
            'metodo_pago': request.session.get('metodo_pago'),
        }
        return render(request, 'reservations/step3.html', context)

    def post(self, request):
        if 'nombre_cliente' not in request.session or 'metodo_pago' not in request.session:
            messages.warning(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:step1')

        sesion_id = obtener_sesion_id(request)
        items = ItemCesta.objects.filter(sesion_id=sesion_id)

        if not items.exists():
            messages.warning(request, 'La cesta está vacía.')
            return redirect('reservations:cart')

        metodo_pago = request.session.get('metodo_pago')

        for item in items:
            total = calcular_precio_reserva(
                item.barco,
                item.fecha_inicio,
                item.fecha_fin,
                item.cantidad
            )

            reserva = Reserva.objects.create(
                cliente=request.user if request.user.is_authenticated else None,
                nombre_cliente=request.session.get('nombre_cliente'),
                email_contacto=request.session.get('email_contacto'),
                telefono=request.session.get('telefono', ''),
                barco=item.barco,
                cantidad=item.cantidad,
                fecha_inicio=item.fecha_inicio,
                fecha_fin=item.fecha_fin,
                importe_total=total,
                metodo_pago=metodo_pago,
            )

            CambioEstadoReserva.objects.create(
                reserva=reserva,
                estado_anterior='',
                estado_nuevo='PENDIENTE_DE_PAGO',
                usuario=request.user if request.user.is_authenticated else None,
            )

            enviar_confirmacion_reserva(reserva)

            if metodo_pago == 'PAYPAL':
                request.session['reserva_id'] = reserva.id
                return redirect('reservations:paypal_checkout')

        ItemCesta.objects.filter(sesion_id=sesion_id).delete()
        request.session.flush()

        messages.success(request, 'Reserva creada exitosamente.')
        return redirect('reservations:confirmation')


class PayPalCheckoutView(View):
    def get(self, request):
        reserva_id = request.session.get('reserva_id')
        if not reserva_id:
            messages.error(request, 'No hay reserva para procesar.')
            return redirect('reservations:cart')

        try:
            reserva = Reserva.objects.get(id=reserva_id)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return redirect('reservations:cart')

        paypal_service = PayPalService()
        return_url = request.build_absolute_uri(reverse('reservations:paypal_return'))
        cancel_url = request.build_absolute_uri(reverse('reservations:paypal_cancel'))

        pago = paypal_service.crear_pago(reserva, return_url, cancel_url)

        if pago and 'links' in pago:
            for link in pago['links']:
                if link['rel'] == 'approval_url':
                    request.session['payment_id'] = pago['id']
                    return redirect(link['href'])

        messages.error(request, 'Error al procesar el pago con PayPal.')
        return redirect('reservations:step3')


