class CancelReservationView(View):
    @method_decorator(login_required)
    def post(self, request, id):
        reserva = get_object_or_404(Reserva, id=id, cliente=request.user)

        if not reserva.puede_cancelarse():
            messages.error(request, 'No se puede cancelar una reserva que no está pendiente de pago.')
        else:
            estado_anterior = reserva.estado
            reserva.estado = 'CANCELADA'
            reserva.save()

            CambioEstadoReserva.objects.create(
                reserva=reserva,
                estado_anterior=estado_anterior,
                estado_nuevo='CANCELADA',
                usuario=request.user,
            )

            messages.success(request, 'Reserva cancelada exitosamente.')

        return redirect('reservations:my_reservations')

